+
+  private getKeysetOrder(orderBy?: OrderByType<T>): Array<[string, 'asc' | 'desc']> {
+    if (!orderBy) return [];
+
+    const entries = (Array.isArray(orderBy) ? orderBy : [orderBy]).flatMap(
+      (part) => Object.entries(part as Record<string, any>),
+    );
+    const order = entries.map(([field, direction]) => [
+      field,
+      this.normalizeSortDirection(direction),
+    ]) as Array<[string, 'asc' | 'desc']>;
+    const idField = this.crudConfig.id_field;
+    if (!order.some(([field]) => field === idField)) {
+      order.push([idField, 'asc']);
+    }
+    return order;
+  }
+
+  private normalizeSortDirection(direction: any): 'asc' | 'desc' {
+    const normalized = String(direction).toLowerCase();
+    if (normalized === 'asc' || normalized === '1') return 'asc';
+    if (normalized === 'desc' || normalized === '-1') return 'desc';
+    throw new BadRequestException('orderBy directions must be asc or desc for cursor pagination');
+  }
+
+  private toMikroOrderBy(order: Array<[string, 'asc' | 'desc']>) {
+    return order.map(([field, direction]) => ({ [field]: direction }));
+  }
+
+  private decodeCursor(
+    cursor: string,
+    order: Array<[string, 'asc' | 'desc']>,
+  ): Record<string, any> {
+    let decoded: any;
+    try {
+      if (
+        !/^(?:[A-Za-z0-9+/]{4})*(?:[A-Za-z0-9+/]{2}==|[A-Za-z0-9+/]{3}=)?$/.test(
+          cursor,
+        )
+      ) {
+        throw new Error('invalid base64');
+      }
+      decoded = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
+    } catch {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+
+    const expectedSort = order.map(([field, direction]) => `${field}:${direction}`).join(',');
+    if (!decoded || typeof decoded !== 'object' || decoded.__sort !== expectedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    for (const [field] of order) {
+      if (!Object.prototype.hasOwnProperty.call(decoded, field)) {
+        throw new BadRequestException(`cursor is missing ${field}`);
+      }
+    }
+    return decoded;
+  }
+
+  private getKeysetPredicate(
+    order: Array<[string, 'asc' | 'desc']>,
+    cursor: Record<string, any>,
+  ) {
+    return {
+      $or: order.map(([field, direction], index) => ({
+        $and: [
+          ...order.slice(0, index).map(([previousField]) => ({
+            [previousField]: cursor[previousField],
+          })),
+          {
+            [field]: {
+              [direction === 'asc' ? '$gt' : '$lt']: cursor[field],
+            },
+          },
+        ],
+      })),
+    };
+  }
+
+  private encodeCursor(entity: T, order: Array<[string, 'asc' | 'desc']>) {
+    const cursor: Record<string, any> = {
+      __sort: order.map(([field, direction]) => `${field}:${direction}`).join(','),
+    };
+    for (const [field] of order) {
+      cursor[field] = this.getEntityValue(entity, field);
+    }
+    return Buffer.from(JSON.stringify(cursor)).toString('base64');
+  }
+
+  private getEntityValue(entity: T, field: string) {
+    return field.split('.').reduce((value, key) => value?.[key], entity as any);
+  }
